	IssueID     string `json:"issueID"`
	DependsOnID string `json:"dependsOnID"`
	Type        string `json:"type"`
	CreatedAt   string `json:"createdAt,omitempty"`
	CreatedBy   string `json:"createdBy,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

type GetBeadResponse struct {
	DDXBead *Bead `json:"ddxBead,omitempty"`
}

type ListBeadsResponse struct {
	DDXBeads []Bead `json:"ddxBeads,omitempty"`
}

type CreateBeadResponse struct {
	CreateEntity *Bead `json:"createEntity,omitempty"`
}

type UpdateBeadResponse struct {
	UpdateEntity *Bead `json:"updateEntity,omitempty"`
}

const (
	getBeadQuery       = `query GetBead($id: ID!) { ddxBead(id: $id) { ...BeadFields } }`
	listBeadsQuery     = `query ListBeads { ddxBeads { ...BeadFields } }`
	createBeadMutation = `mutation CreateBead($input: BeadInput!) { createEntity(input: $input) { ...BeadFields } }`
	updateBeadMutation = `mutation UpdateBead($id: ID!, $expectedVersion: Int!, $input: BeadInput!) { updateEntity(id: $id, expectedVersion: $expectedVersion, input: $input) { ...BeadFields } }`
)

// GetBead loads one bead by ID.
func (c *Client) GetBead(ctx context.Context, id string) (*Bead, error) {
	var resp GetBeadResponse
	if err := c.transport.Query(ctx, getBeadQuery, map[string]any{"id": id}, &resp); err != nil {
		return nil, err
	}
	return resp.DDXBead, nil
}

// ListBeads loads the complete bead collection.
func (c *Client) ListBeads(ctx context.Context) ([]Bead, error) {
	var resp ListBeadsResponse
	if err := c.transport.Query(ctx, listBeadsQuery, nil, &resp); err != nil {
		return nil, err
	}
	return resp.DDXBeads, nil
}

// CreateBead inserts a new bead and returns the server materialization.
func (c *Client) CreateBead(ctx context.Context, input BeadInput) (*Bead, error) {
	var resp CreateBeadResponse
	if err := c.transport.Query(ctx, createBeadMutation, map[string]any{"input": input}, &resp); err != nil {
		return nil, err
	}
	return resp.CreateEntity, nil
}

// UpdateBead updates an existing bead with optimistic concurrency control.
func (c *Client) UpdateBead(ctx context.Context, id string, expectedVersion int, input BeadInput) (*Bead, error) {
	var resp UpdateBeadResponse
	vars := map[string]any{"id": id, "expectedVersion": expectedVersion, "input": input}
	if err := c.transport.Query(ctx, updateBeadMutation, vars, &resp); err != nil {
		return nil, err
	}
	return resp.UpdateEntity, nil
}

// BeadFromLocal copies the local bead model into the generated GraphQL type.
func BeadFromLocal(src bead.Bead) Bead {
	dst := Bead{
		ID:          src.ID,
		Title:       src.Title,
		Status:      src.Status,
		Priority:    src.Priority,
		IssueType:   src.IssueType,
		Owner:       src.Owner,
		CreatedAt:   src.CreatedAt,
		CreatedBy:   src.CreatedBy,
		UpdatedAt:   src.UpdatedAt,
		Labels:      append([]string(nil), src.Labels...),
		Parent:      src.Parent,
		Description: src.Description,
		Acceptance:  src.Acceptance,
		Notes:       src.Notes,
		Extra:       cloneStringAnyMap(src.Extra),
	}
	if len(src.Dependencies) > 0 {
		dst.Dependencies = make([]Dependency, 0, len(src.Dependencies))
		for _, dep := range src.Dependencies {
			dst.Dependencies = append(dst.Dependencies, Dependency{
				IssueID:     dep.IssueID,
				DependsOnID: dep.DependsOnID,
				Type:        dep.Type,
				CreatedAt:   dep.CreatedAt,
				CreatedBy:   dep.CreatedBy,
				Metadata:    dep.Metadata,
			})
		}
	}
	return dst
}

// ToLocal copies the GraphQL bead type back into the local bead model.
func (b Bead) ToLocal() bead.Bead {
	dst := bead.Bead{
		ID:          b.ID,
		Title:       b.Title,
		Status:      b.Status,
		Priority:    b.Priority,
		IssueType:   b.IssueType,
		Owner:       b.Owner,
		CreatedAt:   b.CreatedAt,
		CreatedBy:   b.CreatedBy,
		UpdatedAt:   b.UpdatedAt,
		Labels:      append([]string(nil), b.Labels...),
		Parent:      b.Parent,
		Description: b.Description,
		Acceptance:  b.Acceptance,
		Notes:       b.Notes,
		Extra:       cloneStringAnyMap(b.Extra),
	}
	if len(b.Dependencies) > 0 {
		dst.Dependencies = make([]bead.Dependency, 0, len(b.Dependencies))
		for _, dep := range b.Dependencies {
			dst.Dependencies = append(dst.Dependencies, bead.Dependency{
				IssueID:     dep.IssueID,
				DependsOnID: dep.DependsOnID,
				Type:        dep.Type,
				CreatedAt:   dep.CreatedAt,
				CreatedBy:   dep.CreatedBy,
				Metadata:    dep.Metadata,
			})
		}
	}
	return dst
}

