func decodeBeadEvents(raw any) []BeadEvent {
	switch v := raw.(type) {
	case []BeadEvent:
		out := make([]BeadEvent, len(v))
		copy(out, v)
		return out
	case []any:
		out := make([]BeadEvent, 0, len(v))
		for _, item := range v {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			out = append(out, beadEventFromMap(m))
		}
		return out
	case []map[string]any:
		out := make([]BeadEvent, 0, len(v))
		for _, item := range v {
			out = append(out, beadEventFromMap(item))
		}
		return out
	default:
		return nil
	}
}

func beadEventFromMap(m map[string]any) BeadEvent {
	e := BeadEvent{}
	if v, ok := m["kind"].(string); ok {
		e.Kind = v
	}
	if v, ok := m["summary"].(string); ok {
		e.Summary = v
	}
	if v, ok := m["body"].(string); ok {
		e.Body = v
	}
	if v, ok := m["actor"].(string); ok {
		e.Actor = v
	}
	if v, ok := m["source"].(string); ok {
		e.Source = v
	}
	if v, ok := m["created_at"].(string); ok {
		if parsed, err := time.Parse(time.RFC3339, v); err == nil {
			e.CreatedAt = parsed
		}
	}
	return e
}

